import io.grpc.*;
import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class FileUploadService extends FileUploadGrpc.FileUploadImplBase {

    @Override
    public void fileUpload(FileUploadRequest request, StreamObserver<FileUploadResponse> responseObserver) {
        String fileName = request.getFileName();
        byte[] fileContent = new byte[request.getFileLength()];
        
        // Read the file content from the client
        for (int i = 0; i < request.getFileLength(); i++) {
            FileUploadRequest.FileChunk chunk = request.getFileChunks(i);
            System.arraycopy(chunk.getData(), 0, fileContent, i * chunk.getChunkLength(), chunk.getChunkLength());
        }
        
        // Process the uploaded file content
        // For this example, we'll just store it in memory.
        String processedFileContent = new String(fileContent);
        
        FileUploadResponse response = FileUploadResponse.newBuilder()
                .setProcessedFileContent(processedFileContent)
                .build();
        
        responseObserver.onNext(response);
        responseObserver.onCompleted();
    }
}

